{
  "name": "ax-next",
  "version": "0.0.0",
  "private": true,
  "description": "AX v2 ŌĆö plugin-based personal AI agent (greenfield rewrite)",
  "license": "MIT",
  "type": "module",
  "engines": {
    "node": ">=24.0.0",
    "pnpm": ">=10.0.0"
  },
  "packageManager": "pnpm@10.23.0",
  "scripts": {
    "build": "tsc --build",
    "build:clean": "tsc --build --clean",
    "test": "pnpm -r run test",
    "lint": "eslint .",
    "typecheck": "tsc --build --noEmit",
    "changeset": "changeset",
    "version-packages": "changeset version",
    "release": "pnpm build && changeset publish"
  },
  "devDependencies": {
    "@changesets/cli": "^2.31.0",
    "@types/node": "^25.6.0",
    "eslint": "^10.2.1",
    "typescript": "^6.0.3",
    "typescript-eslint": "^8.59.0",
    "vitest": "^4.1.4"
  }
}
{
  "$schema": "https://json.schemastore.org/tsconfig",
  "compilerOptions": {
    "target": "ES2023",
    "module": "NodeNext",
    "moduleResolution": "NodeNext",
    "lib": ["ES2023"],
    "types": ["node"],

    "strict": true,
    "noUncheckedIndexedAccess": true,
    "noImplicitOverride": true,
    "noFallthroughCasesInSwitch": true,
    "exactOptionalPropertyTypes": true,

    "esModuleInterop": true,
    "skipLibCheck": true,
    "forceConsistentCasingInFileNames": true,
    "resolveJsonModule": true,
    "isolatedModules": true,
    "verbatimModuleSyntax": true,

    "declaration": true,
    "declarationMap": true,
    "sourceMap": true,
    "composite": true,
    "incremental": true,

    "outDir": "dist",
    "rootDir": "src"
  },
  "exclude": ["**/dist", "**/node_modules"]
}
{
  "extends": "./tsconfig.base.json",
  "files": [],
  "references": []
}
packages:
  - 'packages/*'
  - 'presets/*'
// AX v2 ŌĆö flat ESLint config.
//
// The important rule here is `no-restricted-imports`, which enforces CLAUDE.md
// invariant 2: "plugins talk through the hook bus, not direct imports."
//
// Allowed @ax/* imports:
//   @ax/core          ŌĆö the kernel, every plugin depends on it
//   @ax/test-harness  ŌĆö test-only, not in plugin runtime paths
//
// Exceptions (rule turned off):
//   packages/cli/**   ŌĆö the CLI loads plugins per ax.config.ts
//   presets/**        ŌĆö presets are meta-packages that reference plugins

import tseslint from 'typescript-eslint';

export default tseslint.config(
  {
    ignores: [
      '**/dist/**',
      '**/node_modules/**',
      '**/*.tsbuildinfo',
      '**/coverage/**',
    ],
  },

  ...tseslint.configs.recommended,

  {
    rules: {
      'no-restricted-imports': [
        'error',
        {
          patterns: [
            {
              group: ['@ax/*', '!@ax/core', '!@ax/test-harness'],
              message:
                'Cross-plugin imports are forbidden. Plugins communicate through the hook bus only. See CLAUDE.md invariant 2. The only @ax/* imports allowed in plugin code are @ax/core and @ax/test-harness.',
            },
          ],
        },
      ],
    },
  },

  {
    files: ['packages/cli/**', 'presets/**'],
    rules: {
      'no-restricted-imports': 'off',
    },
  },
);

